def validate(records, required_fields=("id", "email", "amount")):
    """
    Yields only valid records.
    Logs and skips records that fail validation.
    """
    for record in records:
        errors = []
        for field in required_fields:
            if not record.get(field):
                errors.append(f"Missing field: {field}")
        if record.get("amount") and float(record["amount"]) < 0:
            errors.append("Amount cannot be negative")

        if errors:
            print(f"[VALIDATION FAIL] {record.get('id')}: {errors}")
            continue  # skip bad records, or send to a dead-letter queue

        yield record

from pydantic import BaseModel, EmailStr, validator
from typing import Iterator

class OrderRecord(BaseModel):
    id: int
    email: EmailStr
    amount: float

    @validator("amount")
    def amount_positive(cls, v):
        if v < 0:
            raise ValueError("amount must be non-negative")
        return v

def validate_pydantic(records: Iterator[dict]) -> Iterator[OrderRecord]:
    for record in records:
        try:
            yield OrderRecord(**record)
        except Exception as e:
            print(f"[INVALID] {record}: {e}")

