def enrich_in_batches(records, batch_size=100):
    batch = []
    for record in records:
        batch.append(record)
        if len(batch) >= batch_size:
            emails = [r["email"] for r in batch]
            # One query for the whole batch
            lookup = fetch_customer_data_bulk(emails)
            for r in batch:
                r.update(lookup.get(r["email"], {}))
                yield r
            batch = []
    # Flush remaining records
    if batch:
        emails = [r["email"] for r in batch]
        lookup = fetch_customer_data_bulk(emails)
        for r in batch:
            r.update(lookup.get(r["email"], {}))
            yield r

def sink_postgres_batch(records, connection, table: str, batch_size=500):
    from psycopg2.extras import execute_values
    batch = []
    with connection.cursor() as cur:
        for record in records:
            batch.append(record)
            if len(batch) >= batch_size:
                execute_values(
                    cur,
                    f"INSERT INTO {table} ({', '.join(batch[0].keys())}) VALUES %s",
                    [list(r.values()) for r in batch]
                )
                batch = []
        if batch:
            execute_values(
                cur,
                f"INSERT INTO {table} ({', '.join(batch[0].keys())}) VALUES %s",
                [list(r.values()) for r in batch]
            )
    connection.commit()

def validate_with_dlq(records, dlq_path: str, required_fields=("id", "email")):
    with open(dlq_path, "a") as dlq:
        for record in records:
            errors = [f for f in required_fields if not record.get(f)]
            if errors:
                dlq.write(json.dumps({"record": record, "errors": errors}) + "\n")
            else:
                yield record

from abc import ABC, abstractmethod
from typing import Iterable, Iterator

class PipelineStage(ABC):
    """Base class for all pipeline stages."""

    @abstractmethod
    def process(self, records: Iterable[dict]) -> Iterator[dict]:
        ...

    def __call__(self, records):
        return self.process(records)

class TaxTransform(PipelineStage):
    def __init__(self, rate: float = 0.1):
        self.rate = rate

    def process(self, records):
        for record in records:
            record["tax"] = round(float(record["amount"]) * self.rate, 2)
            yield record

class EmailNormalizer(PipelineStage):
    def process(self, records):
        for record in records:
            record["email"] = record["email"].lower().strip()
            yield record

class Pipeline:
    """Composes multiple stages into a runnable pipeline."""

    def __init__(self, stages: list[PipelineStage]):
        self.stages = stages

    def run(self, source: Iterable[dict], sink_fn):
        data = source
        for stage in self.stages:
            data = stage(data)
        sink_fn(data)

