# BAD — mutates shared dict
def transform_bad(records):
    for record in records:
        record["email"] = record["email"].lower()  # mutates in place
        yield record

# GOOD — produces a new dict
def transform_good(records):
    for record in records:
        yield {**record, "email": record["email"].lower()}
